            font-weight: bold;
            color: #555;
        }

        #result {
            width: 100%;
            height: 100px;
            padding: 10px;
            border: 1px solid #ddd;
            border-radius: 5px;
            background-color: #fafafa;
            font-family: monospace;
            word-break: break-all;
        }
    </style>
</head>
<body>

    <div class="container">
        <h1>Text Reverser</h1>

        <textarea id="inputText" placeholder="Type or paste your text here..."></textarea>

        <button onclick="reverseText()">Reverse Text</button>

        <div class="result-box">
            <label for="result">Reversed Result:</label>
            <textarea id="result" readonly placeholder="Result will appear here..."></textarea>
        </div>
    </div>

    <script>
        function reverseText() {
            // 1. Get the value from the input textarea
            const inputElement = document.getElementById('inputText');
            const resultElement = document.getElementById('result');

            const originalText = inputElement.value;

            // 2. Reverse the string
            // We use the split('') to make an array of characters,
            // .reverse() to flip the array, and .join('') to make it a string again.
            const reversedText = originalText.split('').reverse().join('');

            // 3. Display the result
            resultElement.value = reversedText;
        }

        // Optional: Add an event listener to reverse automatically as you type
        document.getElementById('inputText').addEventListener('input', function() {
            reverseText();
        });
    </script>

</body>
